<script setup lang="ts">
import{Head,Link,useForm}from'@inertiajs/vue3';import{ArrowLeft,ArrowRight,BriefcaseBusiness,Building2,Dumbbell,Heart,Search,ShieldCheck}from'@lucide/vue';import{computed,onMounted,ref}from'vue';import BrandLogo from '../../Components/BrandLogo.vue';
const step=ref(1),sports=ref<any[]>([]);const form=useForm({name:'',email:'',phone:'',password:'',password_confirmation:'',role:'',interested_sports:[] as string[],sport_id:'',position_id:'',club_name:'',playing_level:'',specialisation:'',years_experience:'',organisation_name:'',services:'',bio:'',date_of_birth:'',province:'',city:'',locality:''});const roles=[{value:'athlete',label:'Athlete',hint:'Showcase talent and find opportunities',icon:Dumbbell},{value:'fan',label:'Fan',hint:'Follow athletes and communities',icon:Heart},{value:'coach',label:'Coach',hint:'Train and mentor athletes',icon:ShieldCheck},{value:'referee',label:'Referee',hint:'Build your officiating career',icon:ShieldCheck},{value:'linesman',label:'Linesman',hint:'Showcase officiating experience',icon:ShieldCheck},{value:'scout',label:'Scout',hint:'Discover sporting talent',icon:Search},{value:'agent',label:'Agent',hint:'Represent sporting careers',icon:Search},{value:'club',label:'Club',hint:'Recruit and publish trials',icon:Building2},{value:'academy',label:'Academy',hint:'Develop emerging talent',icon:Building2},{value:'business',label:'Business',hint:'Offer sports products and services',icon:BriefcaseBusiness},{value:'sponsor',label:'Sponsor',hint:'Support talent and campaigns',icon:BriefcaseBusiness}];const positions=computed(()=>sports.value.find(s=>String(s.id)===form.sport_id)?.positions??[]);const title=computed(()=>['Create your SportUniverse account.','Choose how you belong.',form.role==='fan'?'Choose the sports you love.':'Build your sporting identity.','Tell us where your journey is happening.'][step.value-1]);const next=()=>{if(step.value===1&&(!form.name||!form.email||!form.password||!form.password_confirmation))return;if(step.value===2&&!form.role)return;step.value++};const toggle=(name:string)=>form.interested_sports.includes(name)?form.interested_sports=form.interested_sports.filter(s=>s!==name):form.interested_sports.push(name);const submit=()=>form.post('/register');onMounted(async()=>{const r=await fetch('/api/v1/sports',{headers:{Accept:'application/json'}});sports.value=(await r.json()).data??[]});
</script>
<template><Head title="Join SportUniverse"/><div class="design-auth"><aside class="design-auth-hero"><BrandLogo/><div><h1>{{title}}</h1><p>{{step===1?'Start with your account details.':step===2?'Your role personalises your feed and opportunities.':step===3?'Tell us what should shape your SportUniverse experience.':'Location helps surface nearby talent, clubs and opportunities.'}}</p></div><small>Step {{step}} of 4</small></aside><section class="design-auth-form"><div class="design-auth-top"><div class="design-dots"><i v-for="n in 4" :key="n" :class="{on:n<=step}"/></div><p>Step {{step}} of 4</p></div><div class="design-form-inner"><h2>{{['Account basics','Select your role',form.role==='fan'?'Favourite sports':'Profile details','Age and location'][step-1]}}</h2><p>{{step===3&&form.role==='fan'?'Your For You feed will use these choices.':'You can update these details later from your profile.'}}</p><form @submit.prevent="step<4?next():submit()"><div v-if="step===1" class="form-stack"><label><span class="su-label">Full name</span><input v-model="form.name" class="su-input" required/></label><div class="auth-field-row"><label><span class="su-label">Email</span><input v-model="form.email" class="su-input" type="email" required/></label><label><span class="su-label">Phone</span><input v-model="form.phone" class="su-input" placeholder="+27"/></label></div><label><span class="su-label">Password</span><input v-model="form.password" class="su-input" type="password" required/></label><label><span class="su-label">Confirm password</span><input v-model="form.password_confirmation" class="su-input" type="password" required/></label></div><div v-else-if="step===2" class="role-grid"><button v-for="r in roles" :key="r.value" type="button" class="role-card" :class="{selected:form.role===r.value}" @click="form.role=r.value"><span class="role-icon"><component :is="r.icon"/></span><strong>{{r.label}}</strong><small>{{r.hint}}</small></button></div><div v-else-if="step===3" class="form-stack"><template v-if="form.role==='fan'"><div class="interest-grid"><button v-for="sport in sports" :key="sport.id" type="button" :class="{selected:form.interested_sports.includes(sport.name)}" @click="toggle(sport.name)">{{sport.name}}<small>{{form.interested_sports.includes(sport.name)?'Selected':'Add to feed'}}</small></button></div><p class="interest-note">Choose at least one sport for a personalised feed.</p></template><template v-else-if="form.role==='athlete'"><div class="auth-field-row"><label><span class="su-label">Primary sport</span><select v-model="form.sport_id" class="su-input"><option value="">Select sport</option><option v-for="s in sports" :key="s.id" :value="String(s.id)">{{s.name}}</option></select></label><label><span class="su-label">Position</span><select v-model="form.position_id" class="su-input"><option value="">Select position</option><option v-for="p in positions" :key="p.id" :value="String(p.id)">{{p.name}}</option></select></label></div><label><span class="su-label">Club / school / academy</span><input v-model="form.club_name" class="su-input"/></label><label><span class="su-label">Playing level</span><input v-model="form.playing_level" class="su-input"/></label><label><span class="su-label">Short bio</span><textarea v-model="form.bio" class="su-input registration-bio"/></label></template><template v-else><label><span class="su-label">Short description</span><textarea v-model="form.bio" class="su-input registration-bio"/></label></template></div><div v-else class="form-stack"><label><span class="su-label">Date of birth</span><input v-model="form.date_of_birth" class="su-input" type="date"/></label><div class="auth-field-row"><label><span class="su-label">Province</span><select v-model="form.province" class="su-input"><option value="">Select province</option><option v-for="p in ['Eastern Cape','Free State','Gauteng','KwaZulu-Natal','Limpopo','Mpumalanga','North West','Northern Cape','Western Cape']" :key="p">{{p}}</option></select></label><label><span class="su-label">City / town</span><input v-model="form.city" class="su-input"/></label></div><label><span class="su-label">Township / suburb / village</span><input v-model="form.locality" class="su-input"/></label><p v-if="Object.keys(form.errors).length" class="error">{{Object.values(form.errors)[0]}}</p></div><div class="registration-actions"><button v-if="step>1" type="button" class="su-btn su-btn-ghost" @click="step--"><ArrowLeft/>Back</button><button class="su-btn su-btn-primary" :disabled="form.processing||step===2&&!form.role||step===3&&form.role==='fan'&&!form.interested_sports.length">{{step<4?'Continue':form.processing?'Creating account…':'Complete registration'}}<ArrowRight v-if="step<4"/></button></div></form><p class="auth-footer">Already a member? <Link href="/login">Sign in</Link></p></div></section></div></template>
